19	const applyPercent = (amount: number, percent: number): number =>
20	  Math.ceil((amount * percent) / 100);
21	
22	const applyPercentIf = (condition: boolean, amount: number, percent: number): number =>
23	  condition ? applyPercent(amount, percent) : amount;
