38	const rawBaseFor = (items: any[]): number =>
39	  isThreeAlikeBundle(items)
40	    ? THREE_ALIKE_BUNDLE_BASE
41	    : basePriceByItemType[items[0].type];
42	
43	const isLoyalCustomer = (yearsWithMHPCO: number): boolean =>
44	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
45	
46	const REPEAT_CONTRACT_DISCOUNT_PERCENT = 15;
47	
48	const applyContractAdjustment = (amount: number, isRepeatContract: boolean): number =>
49	  isRepeatContract
50	    ? applyDiscount(amount, REPEAT_CONTRACT_DISCOUNT_PERCENT)
51	    : applyPercent(amount, FIRST_INSURANCE_PERCENT);
52	
53	const quotePremium = (items: any[], yearsWithMHPCO: number, isRepeatContract: boolean): number => {
54	  const base = rawBaseFor(items);
55	  const afterCursed = applyPercentIf(anyCursed(items), base, CURSED_PERCENT);
56	  const afterEnchantment = applyPercentIf(
57	    anyHighlyEnchanted(items),
58	    afterCursed,
59	    ENCHANTMENT_PERCENT,
60	  );
61	  const afterLoyalty = applyDiscountIf(
62	    isLoyalCustomer(yearsWithMHPCO),
63	    afterEnchantment,
64	    LOYALTY_DISCOUNT_PERCENT,
65	  );
66	  const afterContract = applyContractAdjustment(afterLoyalty, isRepeatContract);
67	  return afterContract + FIXED_FEE;
68	};
