70	const DEDUCTIBLE = 100;
71	
72	const reimbursementPercentFor = (item: any): number =>
73	  item.enchantment >= 8 ? 50 : 0;
74	
75	const computePayout = (items: any[], damages: any[]): number => {
76	  const reimbursement = damages.reduce((sum: number, damage: any) => {
77	    const item = items.find((i) => i.type === damage.itemType);
78	    const percent = item ? reimbursementPercentFor(item) : 0;
79	    return sum + (damage.amount * percent) / 100;
80	  }, 0);
81	  return Math.max(0, reimbursement - DEDUCTIBLE);
82	};
