const quoteStep = (step: any, stepIndex: number, yearsWithMHPCO: number, priorQuoteCount: number) => ({
  result: { premium: quotePremium(step.items, yearsWithMHPCO, priorQuoteCount > 0) },
  insuredItemsByStepIndex: { [stepIndex]: step.items },
