export const runScenario = (scenario: any): unknown => {
  const yearsWithMHPCO = scenario.customer?.yearsWithMHPCO ?? 0;
  const initial = { results: [] as any[], insuredItemsByStepIndex: {} as Record<number, any[]>, priorQuoteCount: 0 };
  const final = scenario.steps.reduce((acc: typeof initial, step: any, index: number) => {
    const processed = step.op === "claim"
      ? claimStep(step, acc.insuredItemsByStepIndex)
      : quoteStep(step, index, yearsWithMHPCO, acc.priorQuoteCount);
    return {
      results: [...acc.results, processed.result],
      insuredItemsByStepIndex: { ...acc.insuredItemsByStepIndex, ...processed.insuredItemsByStepIndex },
      priorQuoteCount: acc.priorQuoteCount + (step.op === "claim" ? 0 : 1),
    };
  }, initial);
  return { results: final.results };
};

